insert into public.events (
  id,
  title,
  summary,
  description,
  event_date,
  start_time,
  end_time,
  location,
  category,
  tags,
  confidence_tags,
  organizer,
  image_url,
  why_recommended,
  external_rsvp_url,
  rsvp_count
)
values
  ('00000000-0000-4000-8000-000000000101', 'Nice People and Free Pizza with Agape San Diego', 'A casual lunchtime hangout in Price Center with free pizza and an easy way to meet people.', 'Join friends and meet new people every Tuesday over free pizza in Price Center East. This is a low-pressure drop-in gathering that is especially good for students who want something social without needing a big plan ahead of time.', '2026-04-14', '12:00 PM', '2:00 PM', 'Price Center, 2nd floor, 2.425', 'Social', array['Free Food', 'Drop-In', 'Lunch'], array['Good First Event', 'Come Solo Friendly', 'Low-Pressure'], 'Center for Ethics and Spirituality', null, 'Free food and a familiar central-campus location make this one of the easiest ways to ease into meeting people.', null, 28),
  ('00000000-0000-4000-8000-000000000102', 'Lavender Sachets @ The Zone', 'A simple creative break between classes with supplies provided in The Zone at Price Center.', 'Stop by The Zone to make your own lavender sachet and take a breather between classes. All supplies are provided for UC San Diego students with a valid student ID, so it works well as an easy campus activity with no prep required.', '2026-04-14', '12:00 PM', '3:00 PM', 'Price Center, The Zone', 'Workshops', array['Drop-In', 'Creative', 'Student ID Required'], array['Low-Pressure', 'Beginner-Friendly', 'Drop-In'], 'Student Health and Well-Being', null, 'It is easy to squeeze in between classes and gives new students a reason to learn where The Zone is.', null, 22),
  ('00000000-0000-4000-8000-000000000103', 'Out and Proud Series Event: Lunch and Craft', 'A bring-your-own-lunch community craft hour in Geisel with strong campus community energy.', 'Join the UC San Diego LGBT Resource Center and Pride Staff Association for a community lunch-and-craft hour during Out and Proud 2026. It is a welcoming space for reflection, conversation, and making connections in a recognizable campus location.', '2026-04-14', '12:00 PM', '1:00 PM', 'Geisel Library, Seuss Room', 'Social', array['Crafts', 'Community', 'BYO Lunch'], array['Small Group', 'Structured Activity', 'Come Solo Friendly'], 'Pride Staff Association', null, 'A defined activity and a well-known library location make this easier to approach than a totally open social event.', null, 18),
  ('00000000-0000-4000-8000-000000000104', 'WC & RRC Latine Student Org Social Mixer', 'A guided social mixer for meeting peers involved in Latine student organizations.', 'The Women''s Center and Raza Resource Centro are hosting an afternoon mixer with guided conversations about gender, culture, identity, and leadership. Students can meet campus organizations, connect with peers, and build community in a more structured environment.', '2026-04-14', '3:30 PM', '5:00 PM', 'Women''s Resource Center', 'Social', array['Community', 'Guided Conversation', 'Leadership'], array['Good First Event', 'Structured Activity', 'Small Group'], 'Raza Resource Centro', null, 'The guided format helps take the pressure out of networking and makes it easier to leave with real campus connections.', 'http://tinyurl.com/latinemixer26', 24),
  ('00000000-0000-4000-8000-000000000105', 'Care Fair', 'A campus resource fair focused on gender-affirming care, support services, and practical help.', 'Join STRIDE for the Spring Gender-Affirming Care Fair to learn about campus resources and support options. Food is provided, and the setting is designed for students who want concrete help and a clearer picture of where to go for care on campus.', '2026-04-15', '11:00 AM', '1:00 PM', 'Price Center, Cross-Cultural Center / Comunidad Room', 'Workshops', array['Campus Resources', 'Free Food', 'Support'], array['Beginner-Friendly', 'Structured Activity', 'Low-Pressure'], 'Student Health and Well-Being', null, 'This is useful for students who want practical support and a clear introduction to real campus resources.', 'https://lgbt.ucsd.edu/events/out-and-proud/index.html#:~:text=for%20actionable%20assistance.-,Care%20Fair,-Hosted%20by%3A%20STRIDE', 30),
  ('00000000-0000-4000-8000-000000000106', 'Cafecito Hour', 'A welcoming community hour with coffee, conversation, and support in Pepper Canyon Hall.', 'Cafecito Hour brings students together to talk about well-being, academic success, and Latinx experiences in a community-centered space. Coffee and light snacks are provided, and bilingual conversation is welcome.', '2026-04-15', '12:00 PM', '1:00 PM', 'RAZA Resource Center (RRC), Pepper Canyon Hall Room 264', 'Social', array['Free Coffee', 'Community', 'Bilingual'], array['Small Group', 'Come Solo Friendly', 'Low-Pressure'], 'Student Health and Well-Being', null, 'It combines an approachable room-sized setting with a campus support space that transfer students may not know yet.', null, 20),
  ('00000000-0000-4000-8000-000000000107', 'Summer Budgeting and Finance Tips Workshop @ The Zone', 'A practical workshop on planning for summer housing, travel, jobs, and changing expenses.', 'Join a University Credit Union advisor at The Zone to learn how to prepare for summer costs, compare job options, and build a short-term budget. It is a focused session for students trying to make smart money choices before the quarter ends.', '2026-04-15', '1:00 PM', '2:00 PM', 'Price Center, The Zone', 'Career', array['Budgeting', 'Practical Skills', 'Summer Planning'], array['Beginner-Friendly', 'Structured Activity', 'No Experience Needed'], 'Student Health and Well-Being', null, 'This is useful for students balancing internships, housing changes, and summer costs for the first time.', null, 16),
  ('00000000-0000-4000-8000-000000000108', 'Mindfulness Studio', 'A guided mindfulness break in Geisel focused on breathwork, grounding, and resetting during the quarter.', 'Step into the RISE Mindfulness Studio for a calming workshop built around visualizations, breathwork, and compassion-based meditation. It is a productive low-pressure break in a recognizable library setting.', '2026-04-15', '2:00 PM', '3:00 PM', 'Geisel Library, Calm-Cave Room', 'Sports & Fitness', array['Mindfulness', 'Wellness', 'Guided'], array['Low-Pressure', 'No Experience Needed', 'Beginner-Friendly'], 'Student Health and Well-Being', null, 'It is a strong fit for students who want a gentle first step into campus wellness spaces without a big crowd.', null, 19),
  ('00000000-0000-4000-8000-000000000109', 'Science Communication Workshop and Panel with Industry Experts', 'A career-focused workshop on translating STEM ideas into compelling stories and professional opportunities.', 'Hosted by the Saltman Quarterly and the School of Biological Sciences Career and Professional Development Program, this session explores science communication skills and related career paths. Students can hear from industry experts and build practical communication skills that stand out across fields.', '2026-04-15', '3:00 PM', '4:30 PM', 'Kavli Auditorium, 3rd Floor, Tata Hall', 'Career', array['STEM', 'Panel', 'Professional Development'], array['Beginner-Friendly', 'Structured Activity'], 'School of Biological Sciences', null, 'It is a good way to explore a career-adjacent event even if you are still figuring out how your major connects to real jobs.', null, 27),
  ('00000000-0000-4000-8000-000000000110', 'Yoga at the Library', 'A free indoor Vinyasa session in Geisel that helps students learn one of campus'' most central spaces.', 'Join the Library and Recreation for indoor Vinyasa Flow in the Geisel Meeting Room. Weekly registration is required, and students should bring a yoga mat and props if possible.', '2026-04-16', '10:00 AM', '11:00 AM', 'Geisel Library, Geisel Meeting Room', 'Sports & Fitness', array['Yoga', 'Free for Students', 'Library'], array['Low-Pressure', 'Beginner-Friendly', 'No Experience Needed'], 'UC San Diego Library', null, 'It pairs a familiar campus landmark with a low-pressure wellness activity that is easy to understand and easy to find.', 'lib.ucsd.edu/libyoga', 21),
  ('00000000-0000-4000-8000-000000000111', 'Transfer Hacks Showcase', 'A transfer-centered showcase of student projects, feedback, and networking in Jacobs Hall.', 'The UC San Diego community is invited to learn about student-led projects from TransferHacks participants and see the winning project announced. Students can mingle, learn, and enjoy light refreshments while getting a feel for the engineering and innovation community on campus.', '2026-04-16', '12:30 PM', '2:30 PM', 'Jacobs Hall, Qualcomm Conference Room', 'Networking', array['Transfer-Focused', 'Student Projects', 'Light Refreshments'], array['Good First Event', 'Structured Activity', 'Come Solo Friendly'], 'Triton Transfer Hub', null, 'It is directly relevant to transfer students and gives a clear reason to visit a major academic building with an easy social script.', 'https://engage-us.ucsd.edu/trac/link.php?l=5hn0QLZ5VlGh', 26),
  ('00000000-0000-4000-8000-000000000112', 'Stress Better: Skills for Managing Stress', 'A quick workshop that mixes a simple craft with practical strategies for handling stress and anxiety.', 'Join Student Health and Well-Being at the Craft Center to learn usable stress-management strategies while making a small craft. The session is designed to help students discover concrete techniques for dealing with stress in a more approachable format.', '2026-04-16', '2:00 PM', '3:00 PM', 'Craft Center, Sixth College, Mosaic Second Floor', 'Workshops', array['Stress Relief', 'Crafts', 'Practical Skills'], array['Beginner-Friendly', 'Structured Activity', 'Low-Pressure'], 'Student Health and Well-Being', null, 'This is an easy entry point for students who want support but feel more comfortable showing up for an activity with a clear structure.', null, 17)
on conflict (id) do update
